  { id:"dracometallic-the-old-man-with-the-canaries",name:"The Old Man with the Canaries",source:"dracometallic",level:36,role:"Soldier",roleModifier:"Solo",xp:0,size:"Large",origin:"Immortal",type:"Humanoid",hp:1645,ac:52,fort:47,ref:45,will:47,initiative:24,perception:32,speed:"8, teleport 5 Action Points 2",resist:["20 cold,","20 fire"],powers:[{name:"Unarmed Attack",action:"Standard",description:"Weapon +41 vs AC; 1d12+20 damage, and the target is dazed until the end of its next turn."},{name:"Gold Dragon Rescue",action:"Standard",description:"Area burst 1 within 30, centered on ally; +41 vs AC; the target is stunned (save ends). Effect: The ally in the origin square gains fly 10 until the end of its next turn."},{name:"Summon Gold Dragon",action:"Standard",description:"Summoning Ranged 20; Bahamut summons a Large gold dragon in an unoccupied space within range. The dragon has speed 8, fly 10 (hover) and, unlike a typical summoned creature, has its own defenses and hit points (all defenses 34; hp 120). Minor Action: +27 vs. AC; 1d12 + 10 damage. Opportunity Attack: +27 vs. AC; 1d12 + 10 damage"},{name:"Bahamut's Blessing",action:"Standard",description:"two targets; Ranged 30; each target gains a +10 bonus to attack rolls, a +10 bonus to skill checks, and a +10 bonus to damage rolls until the end of the target's next turn Bahamut's Cleansing (minor; at-will) two targets; Ranged 30; each target can end one effect a save can end"},{name:"Bahamut's Mercy",action:"Minor",description:"Healing two targets; Ranged 30; each target can spend a healing surge and regain an additional 25 hit points"},{name:"Bahamut Runs Rampant",action:"Standard",recharge:"Encounter",description:"Polymorph Bahamut assumes his draconic form (see Bahamut). Seven Canaries Bahamut has seven trained canaries, which he can transform into gold dragons. Some of his powers use up these canaries. All the canaries return during a short rest. Discorporation ( when bloodied) When Bahamut becomes bloodied, he discorporates and is unable to take physical form for a time."}],alignment:"Lawful Good",languages:["Supernal Skills Arcana +31","Athletics +33","Diplomacy +32","Endurance +34","Heal +32","History +31","Insight +32","Intimidate +32","Religion +31"] }
